create table if not exists conversoes (id serial primary key, plataforma text, valor numeric, moeda text, email text, nome text, referencia text, criado_em timestamptz default now());
insert into conversoes (plataforma, valor, moeda, email, nome, referencia)
values ($1, $2, $3, $4, $5, $6);
